def opaque_counter(n):
    # Initialize internal state
    s = n * 7 + 3
    # Transform and mask to 8 bits
    s = (s ^ (s >> 2)) & 0xFF
    # Conditional adjustment
    if s % 2 == 0:
        s += 17
    else:
        s -= 11
    # Return absolute value
    return abs(s)
